css:
/* Custom adjustments for absolute minimalism */
.btn-primary { letter-spacing: 0.05em; font-weight: 600; }
.bg-theme-surface, .card { border: none !important; box-shadow: 0 4px 24px rgba(0,0,0,0.04) !important; }
#grinds-admin-bar { background-color: rgba(255, 255, 255, 0.85) !important; backdrop-filter: saturate(180%) blur(20px); -webkit-backdrop-filter: saturate(180%) blur(20px); border-top: 1px solid rgba(0,0,0,0.08) !important; }
.bg-checker { background-image: radial-gradient(#d2d2d7 1px, transparent 1px) !important; background-size: 16px 16px !important; background-color: #f5f5f7 !important; }
input.form-control, textarea.form-control, select.form-control { border: 1px solid #d2d2d7 !important; transition: all 0.2s ease; }
input.form-control:focus, textarea.form-control:focus, select.form-control:focus { border-color: #e55330 !important; box-shadow: 0 0 0 3px rgba(229, 83, 48, 0.15) !important; }
